import React, { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { MOCK_PRODUCTS } from '../utils/mockproducts';
import { ChevronDown, SlidersHorizontal, X } from 'lucide-react';

const SIDEBAR_CATEGORIES = {
    'LIVING ROOM': {
        'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
        'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
        'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
        'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
    },
    'BEDROOM': {
        'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
        'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
        'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
    },
    'DINING': {
        'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
        'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
        'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
    },
    'STUDY': {
        'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
        'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
        'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
    }
};

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();

    const [selectedCategory, setSelectedCategory] = useState(searchParams.get('category') || 'all');
    const [selectedSubcategory, setSelectedSubcategory] = useState(searchParams.get('subcategory') || searchParams.get('search') || '');
    const [activeAccordion, setActiveAccordion] = useState(() => {
        const cat = searchParams.get('category');
        return cat ? cat.toUpperCase() : null;
    });
    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);
    const [isMobileFiltersOpen, setIsMobileFiltersOpen] = useState(false);

    const { items: apiItems, loading, error } = useSelector((state) => state.products);

    const items = useMemo(() => {
        return (apiItems && apiItems.length > 0) ? apiItems : MOCK_PRODUCTS;
    }, [apiItems]);

    const useMockData = useMemo(() => {
        return (!apiItems || apiItems.length === 0);
    }, [apiItems]);

    // ── Sync state when URL params change ──
    useEffect(() => {
        const cat = searchParams.get('category') || 'all';
        const sub = searchParams.get('subcategory') || '';
        const search = searchParams.get('search') || '';
        setSelectedCategory(cat);
        setSelectedSubcategory(sub || search);
        setActiveAccordion(cat !== 'all' ? cat.toUpperCase() : null);
        setPage(1);
    }, [searchParams]);

    // ── Filter: match category + subcategory + item_type ──
    const filteredProducts = useMemo(() => {
        return items.filter(product => {
            const productCategory = (product.category || '').toLowerCase();
            const productSubcategory = (product.subcategory || '').toLowerCase();
            const productItemType = (product.item_type || '').toLowerCase();
            const productName = (product.name || '').toLowerCase();

            if (selectedSubcategory) {
                const sub = selectedSubcategory.toLowerCase();
                return (
                    productSubcategory === sub ||
                    productItemType === sub ||
                    productSubcategory.includes(sub) ||
                    productItemType.includes(sub) ||
                    productName.includes(sub)
                );
            }

            if (selectedCategory && selectedCategory !== 'all') {
                return productCategory === selectedCategory.toLowerCase();
            }

            return true;
        });
    }, [items, selectedCategory, selectedSubcategory]);

    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const priceA = a.variants?.[0]?.price || 0;
            const priceB = b.variants?.[0]?.price || 0;
            switch (sortBy) {
                case 'price_low': return priceA - priceB;
                case 'price_high': return priceB - priceA;
                case 'popular': return (b.rating || 0) - (a.rating || 0);
                case 'rating': return (b.rating || 0) - (a.rating || 0);
                default: return 0;
            }
        });
    }, [filteredProducts, sortBy]);

    const startIdx = (page - 1) * 20;
    const paginatedProducts = sortedProducts.slice(startIdx, startIdx + 20);
    const calculatedTotalPages = Math.ceil(sortedProducts.length / 20);

    useEffect(() => {
        const params = { page, limit: 20 };
        if (selectedCategory !== 'all') params.category = selectedCategory;
        if (selectedSubcategory) params.subcategory = selectedSubcategory;
        if (sortBy !== 'newest') params.sort = sortBy;
        if (!useMockData) dispatch(fetchProducts(params));
    }, [dispatch, selectedCategory, selectedSubcategory, sortBy, page, useMockData]);

    useEffect(() => {
        if (isMobileFiltersOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }
        return () => { document.body.style.overflow = 'unset'; };
    }, [isMobileFiltersOpen]);

    const handleMainCategoryClick = (mainCat) => {
        setActiveAccordion(activeAccordion === mainCat ? null : mainCat);
        setSelectedCategory(mainCat);
        setSelectedSubcategory('');
        setPage(1);
        const newParams = new URLSearchParams();
        newParams.set('category', mainCat);
        setSearchParams(newParams);
    };

    const handleSubCategoryClick = (subCat) => {
        setSelectedSubcategory(subCat);
        setPage(1);
        const newParams = new URLSearchParams();
        if (selectedCategory && selectedCategory !== 'all') newParams.set('category', selectedCategory);
        newParams.set('subcategory', subCat);
        setSearchParams(newParams);
        if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        if (selectedSubcategory) return selectedSubcategory;
        if (selectedCategory === 'all') return 'All Products';
        return selectedCategory.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
    };

    if (error && !useMockData) {
        return (
            <div className="bg-gray-50 min-h-screen py-12">
                <div className="container mx-auto px-4 text-center">
                    <h1 className="text-3xl font-bold text-red-600 mb-4">Error Loading Products</h1>
                    <p className="text-gray-600 mb-6">{error}</p>
                    <button onClick={() => window.location.reload()} className="bg-gray-900 text-white px-6 py-3 rounded-lg font-semibold hover:bg-gray-800 transition outline-none focus:outline-none focus:ring-0 border-none">
                        Try Again
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-50 min-h-screen">
            <div className="bg-white border-b border-gray-100 py-6 md:py-8">
                <div className="container mx-auto px-4">
                    <div className="mb-4">
                        <button
                            onClick={() => navigate('/')}
                            className="text-gray-500 text-sm hover:text-gray-900 transition-colors flex items-center gap-2 outline-none focus:outline-none border-none select-none bg-transparent"
                            style={{ WebkitTapHighlightColor: 'transparent' }}
                        >
                            <span>←</span> Back to Home
                        </button>
                    </div>
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                        <div>
                            <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-2 tracking-tight">
                                {getDisplayCategory()}
                            </h1>
                            <p className="text-gray-500 text-sm md:text-base font-medium select-none">
                                Showing {paginatedProducts.length > 0 ? startIdx + 1 : 0}–
                                {startIdx + paginatedProducts.length} of {sortedProducts.length} products
                                {useMockData && <span className="text-orange-400 ml-2 font-medium">(Demo Data)</span>}
                            </p>
                        </div>
                        <button
                            onClick={() => setIsMobileFiltersOpen(true)}
                            className="md:hidden flex items-center justify-center gap-2 w-full bg-white border border-gray-200 text-gray-800 py-3.5 rounded-lg font-semibold shadow-sm hover:bg-gray-50 transition-colors outline-none focus:outline-none focus:ring-0 select-none"
                            style={{ WebkitTapHighlightColor: 'transparent' }}
                        >
                            <SlidersHorizontal size={18} />
                            Filter & Sort
                        </button>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 py-8 md:py-12">
                <div className="grid grid-cols-12 gap-6 md:gap-8">

                    {isMobileFiltersOpen && (
                        <div
                            className="fixed inset-0 bg-gray-900/40 backdrop-blur-[2px] z-40 md:hidden"
                            onClick={() => setIsMobileFiltersOpen(false)}
                        />
                    )}

                    <div className={`
                        fixed inset-y-0 left-0 z-50 w-[85%] max-w-[340px] bg-white shadow-2xl flex flex-col transform transition-transform duration-300 ease-in-out
                        md:static md:z-auto md:w-auto md:max-w-none md:bg-transparent md:shadow-none md:transform-none md:translate-x-0 md:block
                        col-span-12 md:col-span-3
                        ${isMobileFiltersOpen ? 'translate-x-0' : '-translate-x-full'}
                    `}>
                        <div className="flex items-center justify-between p-5 border-b border-gray-100 md:hidden bg-white shrink-0">
                            <h2 className="text-xl font-bold text-gray-900 tracking-tight">Filters</h2>
                            <button
                                onClick={() => setIsMobileFiltersOpen(false)}
                                className="p-2 -mr-2 text-gray-400 hover:text-gray-900 bg-gray-50 rounded-full outline-none focus:outline-none focus:ring-0"
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                <X size={20} />
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-5 md:p-0">
                            <div className="md:sticky md:top-24 space-y-6">
                                <div className="bg-white rounded-xl border border-gray-100 p-5">
                                    <h3 className="text-lg font-bold text-gray-900 mb-5 tracking-tight px-1">Categories</h3>
                                    <div className="space-y-1">

                                        {/* All Products */}
                                        <button
                                            onClick={() => {
                                                setSelectedCategory('all');
                                                setSelectedSubcategory('');
                                                setActiveAccordion(null);
                                                setPage(1);
                                                setSearchParams(new URLSearchParams());
                                            }}
                                            className={`w-full text-left px-4 py-3 rounded-lg transition-all duration-200 font-semibold text-[15px] outline-none focus:outline-none border border-transparent select-none ${selectedCategory === 'all' && !selectedSubcategory
                                                ? 'bg-gray-900 text-white shadow-md'
                                                : 'bg-transparent text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                                                }`}
                                            style={{ WebkitTapHighlightColor: 'transparent' }}
                                        >
                                            All Products
                                        </button>

                                        {/* Main Category Accordions */}
                                        {Object.keys(SIDEBAR_CATEGORIES).map((mainCat) => (
                                            <div key={mainCat} className="flex flex-col">
                                                <button
                                                    onClick={() => handleMainCategoryClick(mainCat)}
                                                    className={`w-full flex items-center justify-between px-4 py-3 rounded-lg transition-all duration-200 font-semibold text-[15px] border border-transparent outline-none focus:outline-none focus:ring-0 select-none ${activeAccordion === mainCat
                                                        ? 'bg-[#fff7ed] text-[#f97316] shadow-sm shadow-orange-100/50'
                                                        : 'bg-transparent text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                                                        }`}
                                                    style={{ WebkitTapHighlightColor: 'transparent' }}
                                                >
                                                    <span className="capitalize tracking-wide">{mainCat.toLowerCase()}</span>
                                                    <ChevronDown
                                                        size={18}
                                                        className={`transition-transform duration-300 ease-out ${activeAccordion === mainCat ? 'rotate-180 text-[#f97316]' : 'text-gray-400'}`}
                                                    />
                                                </button>

                                                <div className={`grid transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] ${activeAccordion === mainCat ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                                                    <div className="overflow-hidden">
                                                        <div className="pl-2 pr-2 space-y-5 py-3 border-l-2 border-gray-100 ml-6 my-2">
                                                            {Object.entries(SIDEBAR_CATEGORIES[mainCat]).map(([groupName, groupItems]) => (
                                                                <div key={groupName}>
                                                                    <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-3 select-none px-4">{groupName}</h4>
                                                                    <ul className="space-y-1">
                                                                        {groupItems.map(item => (
                                                                            <li key={item}>
                                                                                {/* 🚀 FIXED CSS: Added border border-transparent to block ghost lines, maintained soft shadow */}
                                                                                <button
                                                                                    onClick={() => handleSubCategoryClick(item)}
                                                                                    className={`text-sm text-left w-full py-2.5 px-4 rounded-md transition-all duration-200 flex items-center relative border border-transparent outline-none focus:outline-none focus:ring-0 select-none ${selectedSubcategory === item
                                                                                        ? 'bg-[#fff7ed] text-[#f97316] font-bold shadow-[0_2px_8px_rgba(249,115,22,0.12)]'
                                                                                        : 'bg-transparent text-gray-500 hover:bg-gray-50 hover:text-gray-900 font-medium'
                                                                                        }`}
                                                                                    style={{ WebkitTapHighlightColor: 'transparent' }}
                                                                                >
                                                                                    <span className={`absolute left-3 w-1.5 h-1.5 rounded-full bg-[#f97316] transition-opacity duration-200 ${selectedSubcategory === item ? 'opacity-100' : 'opacity-0'}`}></span>
                                                                                    <span className="pl-4">{item}</span>
                                                                                </button>
                                                                            </li>
                                                                        ))}
                                                                    </ul>
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                {/* Sort By */}
                                <div className="bg-white rounded-xl border border-gray-100 p-5">
                                    <h3 className="text-lg font-bold text-gray-900 mb-4 tracking-tight px-1">Sort By</h3>
                                    <div className="relative">
                                        <select
                                            value={sortBy}
                                            onChange={handleSortChange}
                                            className="w-full px-4 py-3 border border-gray-200 rounded-lg text-gray-700 text-sm font-medium outline-none focus:outline-none focus:border-gray-300 transition-all cursor-pointer bg-white appearance-none select-none hover:border-gray-300"
                                            style={{ WebkitAppearance: 'none' }}
                                        >
                                            <option value="newest">Newest Arrivals</option>
                                            <option value="price_low">Price: Low to High</option>
                                            <option value="price_high">Price: High to Low</option>
                                            <option value="popular">Most Popular</option>
                                            <option value="rating">Top Rated</option>
                                        </select>
                                        <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Mobile drawer footer */}
                        <div className="p-4 bg-white border-t border-gray-100 md:hidden shrink-0">
                            <button
                                onClick={() => setIsMobileFiltersOpen(false)}
                                className="w-full bg-gray-900 text-white font-bold py-3.5 rounded-lg hover:bg-gray-800 active:scale-[0.98] transition-all outline-none focus:outline-none border-0"
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                Show {filteredProducts.length} Results
                            </button>
                        </div>
                    </div>

                    {/* Products Grid */}
                    <div className="col-span-12 md:col-span-9">
                        {loading && items.length === 0 ? (
                            <div className="flex justify-center items-center py-32">
                                <LoadingSpinner />
                            </div>
                        ) : paginatedProducts.length === 0 ? (
                            <div className="bg-white rounded-xl border border-gray-100 p-12 md:p-16 text-center h-full flex flex-col items-center justify-center">
                                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-6">
                                    <span className="text-2xl">🔍</span>
                                </div>
                                <h3 className="text-2xl font-bold text-gray-900 mb-3 tracking-tight select-none">No Products Found</h3>
                                <p className="text-gray-500 mb-8 max-w-sm select-none">Try adjusting your filters or browse other categories.</p>
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setSelectedSubcategory('');
                                        setActiveAccordion(null);
                                        setSearchParams(new URLSearchParams());
                                    }}
                                    className="bg-gray-900 text-white px-8 py-3.5 rounded-lg font-bold hover:bg-[#f97316] transition-colors duration-300 outline-none focus:outline-none border-none select-none"
                                    style={{ WebkitTapHighlightColor: 'transparent' }}
                                >
                                    View All Products
                                </button>
                            </div>
                        ) : (
                            <>
                                <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6 mb-8">
                                    {paginatedProducts.map((product) => (
                                        <ProductCard key={product.id || product._id} product={product} />
                                    ))}
                                </div>

                                {calculatedTotalPages > 1 && (
                                    <div className="flex flex-wrap justify-center items-center gap-2 py-8 border-t border-gray-100 mt-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-4 py-2 rounded-lg text-gray-600 font-medium hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all outline-none focus:outline-none border-0 select-none"
                                            style={{ WebkitTapHighlightColor: 'transparent' }}
                                        >
                                            Previous
                                        </button>

                                        {Array.from({ length: Math.min(calculatedTotalPages, 5) }, (_, i) => {
                                            const pageNum = page > 3 ? page - 2 + i : i + 1;
                                            return pageNum <= calculatedTotalPages ? pageNum : null;
                                        }).map((p) => p && (
                                            <button
                                                key={p}
                                                onClick={() => setPage(p)}
                                                className={`w-10 h-10 flex items-center justify-center rounded-lg transition-all font-semibold outline-none focus:outline-none border-0 select-none ${page === p ? 'bg-gray-900 text-white shadow-md' : 'text-gray-600 hover:bg-gray-50'}`}
                                                style={{ WebkitTapHighlightColor: 'transparent' }}
                                            >
                                                {p}
                                            </button>
                                        ))}

                                        <button
                                            onClick={() => setPage(Math.min(calculatedTotalPages, page + 1))}
                                            disabled={page === calculatedTotalPages}
                                            className="px-4 py-2 rounded-lg text-gray-600 font-medium hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all outline-none focus:outline-none border-0 select-none"
                                            style={{ WebkitTapHighlightColor: 'transparent' }}
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
